# Category: elasticsearch_no_auth

import time
from datetime import datetime
from elasticsearch import Elasticsearch, NotFoundError
from elasticsearch.helpers import bulk

class ElasticsearchPlatform:
    def __init__(self, host='localhost', port=9200):
        self.es = Elasticsearch(hosts=[{'host': host, 'port': port}], timeout=30)
        self._check_connection()

    def _check_connection(self):
        if not self.es.ping():
            raise ConnectionError("Could not connect to Elasticsearch! Please ensure it's running at localhost:9200.")
        print("Successfully connected to Elasticsearch!")

    def create_index_if_not_exists(self, index_name, mappings=None, settings=None):
        if not self.es.indices.exists(index=index_name):
            index_body = {}
            if settings:
                index_body['settings'] = settings
            if mappings:
                index_body['mappings'] = mappings

            try:
                self.es.indices.create(index=index_name, body=index_body)
                print(f"Index '{index_name}' created successfully.")
            except Exception as e:
                print(f"Error creating index '{index_name}': {e}")
        else:
            print(f"Index '{index_name}' already exists.")

    def index_document(self, index_name, document, doc_id=None):
        try:
            res = self.es.index(index=index_name, id=doc_id, document=document)
            print(f"Document indexed in '{index_name}': {res['_id']}")
            return res['_id']
        except Exception as e:
            print(f"Error indexing document: {e}")
            return None

    def bulk_index_documents(self, index_name, documents):
        actions = [
            {
                "_index": index_name,
                "_id": doc.get("id"), # Optional: if documents have a unique ID field
                "_source": doc
            }
            for doc in documents
        ]
        try:
            success, failed = bulk(self.es, actions, index=index_name)
            print(f"Bulk indexing completed. Successfully indexed: {success}, Failed: {failed}")
            return success, failed
        except Exception as e:
            print(f"Error during bulk indexing: {e}")
            return 0, len(documents)

    def search_documents(self, index_name, query_string=None, fields=None, size=10, from_=0, sort_field=None, sort_order='desc'):
        search_body = {
            "query": {
                "match_all": {} # Default to match_all if no query_string
            }
        }

        if query_string:
            if fields:
                search_body["query"] = {
                    "multi_match": {
                        "query": query_string,
                        "fields": fields,
                        "fuzziness": "AUTO"
                    }
                }
            else:
                search_body["query"] = {
                    "query_string": {
                        "query": query_string
                    }
                }
        
        if sort_field:
            search_body["sort"] = [
                {
                    sort_field: {
                        "order": sort_order
                    }
                }
            ]

        try:
            res = self.es.search(index=index_name, body=search_body, size=size, from_=from_)
            hits = res['hits']['hits']
            print(f"\nFound {res['hits']['total']['value']} documents:")
            for hit in hits:
                print(f"ID: {hit['_id']}, Score: {hit['_score']}, Source: {hit['_source']}")
            return hits
        except NotFoundError:
            print(f"Index '{index_name}' not found.")
            return []
        except Exception as e:
            print(f"Error during search: {e}")
            return []

    def aggregate_logs_by_level(self, index_name, start_time=None, end_time=None):
        query_body = {
            "aggs": {
                "log_levels": {
                    "terms": {
                        "field": "level.keyword"
                    }
                }
            },
            "size": 0 # We only care about aggregations, not hits
        }

        if start_time and end_time:
            query_body["query"] = {
                "range": {
                    "timestamp": {
                        "gte": start_time,
                        "lte": end_time
                    }
                }
            }

        try:
            res = self.es.search(index=index_name, body=query_body)
            buckets = res['aggregations']['log_levels']['buckets']
            print("\nLog Level Aggregation:")
            for bucket in buckets:
                print(f"  Level: {bucket['key']}, Count: {bucket['doc_count']}")
            return buckets
        except NotFoundError:
            print(f"Index '{index_name}' not found.")
            return []
        except Exception as e:
            print(f"Error during aggregation: {e}")
            return []

    def delete_index(self, index_name):
        try:
            if self.es.indices.exists(index=index_name):
                self.es.indices.delete(index=index_name)
                print(f"Index '{index_name}' deleted successfully.")
            else:
                print(f"Index '{index_name}' does not exist.")
        except Exception as e:
            print(f"Error deleting index '{index_name}': {e}")

    def close(self):
        # No explicit close needed for elasticsearch-py client,
        # but good practice to acknowledge if resources were managed.
        print("Elasticsearch client connection closed (implicitly).")


